import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const w=JSON.parse('{"title":"The Rundown AI — 2026-05-04","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-04","date":"2026-05-04T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-04-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-04-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-05/2026-05-04-the-rundown-ai.md"};function s(i,e,m,l,p,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-05-04" tabindex="-1">🗞️ The Rundown AI — 2026-05-04 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-04" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-04&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="ai-shows-its-skills-in-the-emergency-room" tabindex="-1"><a href="https://www.therundown.ai/p/ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">AI shows its skills in the emergency room</a> <a class="header-anchor" href="#ai-shows-its-skills-in-the-emergency-room" aria-label="Permalink to &quot;[AI shows its skills in the emergency room](https://www.therundown.ai/p/ai-shows-its-skills-in-the-emergency-room)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-04</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. AI just beat two attending emergency room physicians across real patient cases in a new Harvard study. The model? OpenAI’s o1-preview, released in… 2024.</p><p>Millions of users are already turning to ChatGPT for health advice every day, but the data shows that AI models (preferably not several generations behind) may be ready for a more formal seat in the exam room alongside the doctor as well.</p><p>In today’s AI rundown:</p><p>Old AI model tops doctors in ER trial</p><p>The Rundown Roundtable: Our AI use cases</p><p>Create converting landing pages in Claude</p><p>Pentagon announces new AI partners</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>OPENAI</p><p>🏥 <a href="https://www.harvardmagazine.com/ai/ai-outperforms-doctors-diagnosis-harvard-study?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Old AI model tops doctors in ER trial</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: A Harvard study <a href="https://www.science.org/doi/10.1126/science.adz4433?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">published</a> in Science just put OpenAI&#39;s o1-preview (released in 2024) through 76 real ER cases, with the AI diagnosing patients more accurately than two physicians, despite using only raw electronic health-record text.</p><p>The details:</p><p>The study compared OpenAI&#39;s o1-preview model with two attending physicians across 76 real ER cases and three decision stages of patient care.</p><p>At initial ER triage, the model gave the correct diagnosis 67.1% of the time, compared to 55.3% and 50.0% for the two physicians.</p><p>The two separate physician reviewers tasked with scoring couldn&#39;t tell which diagnoses came from the model and which came from the humans.</p><p>In one case, the AI <a href="https://www.sciencenews.org/article/ai-help-doctors-help-diagnoses?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">flagged</a> a rare flesh-eating infection in a transplant patient roughly 12 to 24 hours before the treating doctor caught it.</p><p>Why it matters: Millions of people are already using AI daily for health questions, but studies like these are showing the usefulness can also flow the other way to the doctors themselves. If a model generations behind is already beating ER doctors, imagine what the frontier could look like inside the patient care process.</p><p>TOGETHER WITH UNWRAP</p><p>⚡️ <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">See how Oura automates customer feedback analysis</a></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Unwrap’s customer intelligence platform that pulls all your feedback – surveys, reviews, support tickets, social comments– into one view, then uses AI to surface the most actionable insights to deliver them to your inbox. Teams at Perplexity, Stripe and DoorDash rely on Unwrap to ensure no customer voice gets lost.</p><p>With Unwrap you get:</p><p>All customer feedback automatically categorized</p><p>Query feedback using Unwrap Assistant, or in your favorite tools using Unwrap&#39;s MCP</p><p>Real-time alerts from feedback as they arise</p><p>A clear view of customer sentiment</p><p>Unwrap is offering a trial of its tools to Rundown AI subscribers! <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Grab 15 minutes with the team to get set up</a>.</p><p>THE RUNDOWN ROUNDTABLE</p><p>💡 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">The Rundown Roundtable: Our AI use cases</a></p><p><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p>Image source: Ideogram / The Rundown</p><p>The Rundown: The Rundown Roundtable is a weekly feature where we poll members of The Rundown staff about how we use AI in our work and daily lives.</p><p>Jennifer, Tech &amp; Robotics Writer: Last year, my daughter was diagnosed with a rare autoimmune disease. Like any parent in that situation, I wanted to understand everything I could so we could make the best decisions for her care. I used both Gemini and ChatGPT to help me sort through the medical literature, treatment options, possible side effects, and how other countries approach treatment.</p><p>I also turned to ChatGPT to identify the leading specialists in the country — thankfully, our referred doctor turned out to be one of them, which gave us even more reassurance. More than anything, it helped demystify the disease and make us feel confident that we were doing everything we could. She’s doing really well on her medications, and seeing her recover has been an enormous relief.</p><p>Shubham, Editor: I use ChatGPT as a label-reading filter for packaged snacks, uploading product photos and asking it to flag hidden sugars, oils like palm, and preservatives, then compare options against a strict checklist of clean ingredients, minimal processing, and decent macros.</p><p>It’s especially useful for decoding lesser-known, jargon-heavy terms on the back label, translating things like INS numbers, stabilizers, and emulsifiers into plain English so it’s clear what’s actually being consumed. Instead of trusting front-of-pack claims like “multigrain” or “sugar-free,” it breaks down what’s inside, surfaces trade-offs, and narrows choices to the best options available online</p><p>AI TRAINING</p><p>🎨 <a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Design converting landing pages in Claude</a></p><p><a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn to use Anthropic’s new AI design tool — Claude Design — to generate four, high-converting mockup variations of your website’s landing page.</p><p>Step-by-step:</p><p>Go to claude.ai/design, select wireframe, click create, and describe who the page is for, the product, and the action visitors should take. Don’t hit “Send”</p><p>Screenshot a landing page you like (search top pages in your niche), as well as a page that does millions of daily transactions, like Amazon or eBay</p><p>Hit send with the brief and screenshots. Tell Claude to give four variations of the mockup. Answer any follow-up questions and wait 2-5 minutes</p><p>Refine with comments. Click any element and leave a note like &quot;rewrite this CTA to be outcome-specific&quot; or &quot;add a testimonial here.&quot; Claude applies the change</p><p>Pro tip: Click Share &gt; Handoff to Claude Code &gt; Send to Claude Code Web to get Claude Code to build and deploy the final website for you.</p><p>PRESENTED BY SCRUNCH</p><p>🏆 <a href="http://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">AI is your new VIP visitor</a></p><p><a href="https://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Scrunch is the AI Customer Experience Platform that optimizes your site for AI bots — the new VIPs deciding whether your brand gets named, cited, or skipped when someone asks ChatGPT, Perplexity, or Claude about your category.</p><p>With Scrunch, you&#39;ll:</p><p>See how AI reads your site today</p><p>Spot the blockers and content gaps</p><p>Deliver optimized pages straight to AI agents</p><p>Show up in more AI answers</p><p><a href="http://scrunch.com/airundown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Click here to see how AI reads your site</a>.</p><p>AI &amp; THE PENTAGON</p><p>🏛️ <a href="https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Pentagon announces new AI partners</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: The Pentagon <a href="https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">added</a> 8 AI companies to its classified networks while excluding Anthropic, even as the Washington Post reports the new contracts have the same autonomous-weapons and surveillance limits for which Anthropic was blacklisted.</p><p>The details:</p><p>The official agreement list names SpaceX, OpenAI, Google, Nvidia, Reflection, Microsoft, AWS, and Oracle as the companies added to classified networks.</p><p>The Department of War said the new deals will “accelerate the transformation toward establishing the U.S. military as an AI-first fighting force”.</p><p>DoD CTO Emil Michael <a href="https://www.cnbc.com/2026/05/01/pentagon-anthropic-blacklist-mythos-michael.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">told</a> CNBC that Anthropic’s supply-chain risk label still stands, but called its Mythos model a &quot;separate national security moment.&quot;</p><p>Anthropic’s exclusion comes days after the White House came out against a broader Mythos rollout over compute concerns impacting its own access.</p><p>Why it matters: The White House seemingly wants to have its cake and eat it too — both continuing to shun Anthropic while also wanting priority access to its Mythos model despite the blacklist. There are also some interesting names on that list, namely Reflection, which raised $2B from 1789 Capital, a Donald Trump Jr.-backed fund.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🗣️ <a href="https://www.rundown.ai/tools/custom-voices?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Custom Voices</a> - Clone voices with short clips for use in Grok applications</p><p>🦮 <a href="https://www.rundown.ai/tools/codex-pets?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Codex Pets</a> - OAI&#39;s animated companions for tracking active Codex work</p><p>🎶 <a href="https://www.rundown.ai/tools/eleven-music?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">ElevenMusic</a> - Platform for AI song generation, remixing, creator payouts</p><p>🚀 <a href="https://www.rundown.ai/tools/mimo-v2-5-pro?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">MiMo-V2.5-Pro</a> - Xiaomi&#39;s powerful new open-source model</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>OpenAI <a href="https://developers.openai.com/codex/app/settings?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room#codex-pets" target="_blank" rel="noreferrer">shipped</a> Codex Pets, animated desktop companions that let you track agent progress without switching back to the app.</p><p>OpenAI CEO Sam Altman <a href="https://x.com/sama/status/2050357911915028689?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">announced</a> that OpenClaw users can use their ChatGPT subscriptions within the agentic tool, taking a stance against Anthropic’s <a href="https://www.rundown.ai/articles/anthropic-tells-openclaw-users-to-pay-up?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">restrictions</a>.</p><p>Maryland <a href="https://www.nytimes.com/2026/05/01/business/surveillance-pricing-groceries-maryland.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">signed</a> the U.S.’s first ban on AI-driven grocery pricing, with fines up to $25K for stores caught using personalized shopper data to mark up prices.</p><p>SAG-AFTRA <a href="https://deadline.com/2026/05/sag-aftra-studios-reach-new-bigger-deal-amptp-1236879157/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">secured</a> new AI guardrails in its four-year studio deal, with the guild&#39;s negotiator refusing to sign until Hollywood studios made concessions on AI protections.</p><p>A Chinese court <a href="https://www.npr.org/2026/05/01/nx-s1-5807131/tech-worker-china-ai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">ruled</a> that replacing a worker with AI does not legally justify firing them, ordering a tech firm to pay wrongful termination damages.</p><p>COMMUNITY</p><p>🤝 <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Olli T. in Finland:</p><p>&quot;I&#39;m a new real estate investor, and what I&#39;m struggling with is market insights, as in our county, there is no transparency or proper historical information available. With Gemini Pro, I created a concept that analyzes the market information.</p><p>The tool displays all relevant renovation history and future needs and can also generate an investment calculation. I then refined the concept with multiple free AIs (Claude, Codex), one prompt per day, to have a product that fits my needs.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.therundown.ai/p/the-white-house-rethinks-its-anthropic-fight?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">The White House rethinks its Anthropic fight</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/spacex-rocket-to-crash-into-the-moon?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">SpaceX is about to crash into the Moon</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/the-humanoid-baggage-handler-has-landed?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">A humanoid baggage handler has landed</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-design-a-high-converting-landing-page-in-claude-design?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-shows-its-skills-in-the-emergency-room" target="_blank" rel="noreferrer">Create converting landing pages in Claude</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',102)])])}const c=t(o,[["render",s]]);export{w as __pageData,c as default};
